  `}</style>
);

// ============================================================
// AUTOCOMPLETE
// ============================================================
const Autocomplete = ({ opciones, valorId, onChange, placeholder, displayFn, required }) => {
  const [texto, setTexto] = useState('');
  const [abierto, setAbierto] = useState(false);
  const [resaltado, setResaltado] = useState(-1);
  const ref = useRef(null);

  useEffect(() => {
    if (!valorId) { setTexto(''); return; }
    const op = opciones.find(o => o._id === valorId);
    if (op) setTexto(displayFn(op));
  }, [valorId, opciones]);

  useEffect(() => {
    const h = (e) => { if (ref.current && !ref.current.contains(e.target)) setAbierto(false); };
    document.addEventListener('mousedown', h);
    return () => document.removeEventListener('mousedown', h);
  }, []);

  const filtradas = texto.length > 0
    ? opciones.filter(o => displayFn(o).toLowerCase().includes(texto.toLowerCase()))
    : opciones;

  return (
    <div ref={ref} className="co-ac-wrap">
      <input
        className="co-input co-ac-input"
        type="text"
        value={texto}
        placeholder={placeholder}
        autoComplete="off"
        required={required}
        onChange={e => { setTexto(e.target.value); setAbierto(true); if (!e.target.value) onChange(''); }}
        onFocus={() => setAbierto(true)}
        onKeyDown={e => {
          if (!abierto || !filtradas.length) return;
          if (e.key === 'ArrowDown') { e.preventDefault(); setResaltado(r => Math.min(r + 1, filtradas.length - 1)); }
          else if (e.key === 'ArrowUp') { e.preventDefault(); setResaltado(r => Math.max(r - 1, 0)); }
          else if (e.key === 'Enter' && resaltado >= 0) { e.preventDefault(); setTexto(displayFn(filtradas[resaltado])); onChange(filtradas[resaltado]._id); setAbierto(false); }
          else if (e.key === 'Escape') setAbierto(false);
        }}
      />
      <span className="co-ac-icon">⌕</span>
      {abierto && filtradas.length > 0 && (
        <ul className="co-ac-list">
          {filtradas.map((op, i) => (
            <li key={op._id}
              className={`co-ac-item${i === resaltado ? ' co-ac-item--hi' : ''}`}
              onPointerDown={e => { e.preventDefault(); setTexto(displayFn(op)); onChange(op._id); setAbierto(false); }}
              onMouseEnter={() => setResaltado(i)}
            >{displayFn(op)}</li>
          ))}
        </ul>
      )}
      {abierto && texto && !filtradas.length && (
        <div className="co-ac-empty">Sin resultados para "{texto}"</div>
      )}
    </div>
  );
};

