const FormularioCampesena = ({ formData, setFormData }) => {
  const [instructores, setInstructores] = useState([{
    id: Date.now(), tipo: 'Técnico', tipo_identificacion: 'CC',
    identificacion: '', nombre: '', correo: '', celular: '', programacion: []
  }]);

  const sync = (nuevos) => { setInstructores(nuevos); setFormData({ ...formData, instructores: nuevos }); };

  const agregarInstructor = () => sync([...instructores, {
    id: Date.now() + Math.random(), tipo: 'Técnico', tipo_identificacion: 'CC',
    identificacion: '', nombre: '', correo: '', celular: '', programacion: []
  }]);
  const eliminarInstructor = (id) => sync(instructores.filter(i => i.id !== id));
  const actualizarCampo = (id, campo, valor) => sync(instructores.map(i => i.id === id ? { ...i, [campo]: valor } : i));
  const agregarMes = (id) => sync(instructores.map(i => i.id !== id ? i : { ...i, programacion: [...i.programacion, { mes: i.programacion.length + 1, rangos: [] }] }));
  const eliminarMes = (id, mIdx) => sync(instructores.map(i => i.id !== id ? i : { ...i, programacion: i.programacion.filter((_, idx) => idx !== mIdx).map((m, idx) => ({ ...m, mes: idx + 1 })) }));
  const agregarRango = (id, mIdx) => sync(instructores.map(i => i.id !== id ? i : { ...i, programacion: i.programacion.map((m, idx) => idx !== mIdx ? m : { ...m, rangos: [...m.rangos, { desde: '', hasta: '', hora_inicio: '08:00', hora_fin: '16:00' }] }) }));
  const eliminarRango = (id, mIdx, rIdx) => sync(instructores.map(i => i.id !== id ? i : { ...i, programacion: i.programacion.map((m, idx) => idx !== mIdx ? m : { ...m, rangos: m.rangos.filter((_, ri) => ri !== rIdx) }) }));
  const actualizarRango = (id, mIdx, rIdx, campo, valor) => sync(instructores.map(i => i.id !== id ? i : { ...i, programacion: i.programacion.map((m, idx) => idx !== mIdx ? m : { ...m, rangos: m.rangos.map((r, ri) => ri !== rIdx ? r : { ...r, [campo]: valor }) }) }));

  const tipoTag = { 'Técnico': { bg: '#ecfdf5', color: '#065f46' }, 'Empresarial': { bg: '#eff6ff', color: '#1e40af' }, 'Popular': { bg: '#fdf4ff', color: '#6b21a8' } };

  return (
    <div className="co-card" style={{ border: '1.5px solid var(--gold-light)' }}>
      <div className="co-card-head" style={{ background: 'linear-gradient(135deg, #0d1117, #1a4731)' }}>
        <div className="co-card-icon" style={{ background: 'var(--gold)' }}>🌾</div>
        <div>
          <div className="co-card-title" style={{ color: 'var(--cream)' }}>Instructores Campesena</div>
          <div style={{ fontSize: 12, color: 'rgba(245,240,232,.6)', marginTop: 2 }}>Agrega instructores y su programación mensual</div>
        </div>
        <div className="co-card-num" style={{ color: 'var(--gold)', fontFamily: 'var(--font-mono)', fontSize: 22, fontWeight: 700 }}>{instructores.length}</div>
      </div>
      <div className="co-card-body">
        {instructores.map((inst, idx) => {
          const tag = tipoTag[inst.tipo] || tipoTag['Técnico'];
          return (
            <div key={inst.id} className="co-inst-card">
              <div className="co-inst-head">
                <div className="co-inst-head-left">
                  <div className="co-inst-num">{idx + 1}</div>
                  <div>
                    <div className="co-inst-label">Instructor {idx + 1}</div>
                    <span className="co-inst-tag" style={{ background: tag.bg, color: tag.color }}>{inst.tipo}</span>
                  </div>
                </div>
                {instructores.length > 1 && (
                  <button type="button" className="co-btn co-btn--danger" style={{ fontSize: 12, padding: '6px 12px' }}
                    onClick={() => eliminarInstructor(inst.id)}>
                    <Ic.Trash /> Eliminar
                  </button>
                )}
              </div>
              <div className="co-inst-body">
                {/* Tipo */}
                <div className="co-label" style={{ marginBottom: 8 }}>Tipo de instructor</div>
                <div className="co-tipo-row">
                  {['Técnico', 'Empresarial', 'Popular'].map(t => (
                    <button key={t} type="button"
                      className={`co-tipo-chip${inst.tipo === t ? ' co-tipo-chip--active' : ''}`}
                      onClick={() => actualizarCampo(inst.id, 'tipo', t)}>{t}</button>
                  ))}
                </div>

                {/* Datos personales */}
                <div className="co-grid-2">
                  <div className="co-field">
                    <label className="co-label">Tipo ID</label>
                    <select className="co-select" value={inst.tipo_identificacion}
                      onChange={e => actualizarCampo(inst.id, 'tipo_identificacion', e.target.value)}>
                      {['CC','CE','TI','PAP','NIT'].map(v => <option key={v}>{v}</option>)}
                    </select>
                  </div>
                  <div className="co-field">
                    <label className="co-label">Número de identificación</label>
                    <input className="co-input" value={inst.identificacion} placeholder="12345678"
                      onChange={e => actualizarCampo(inst.id, 'identificacion', e.target.value)} />
                  </div>
                </div>
                <div className="co-field">
                  <label className="co-label">Nombre completo</label>
                  <input className="co-input" value={inst.nombre} placeholder="Nombre completo"
                    onChange={e => actualizarCampo(inst.id, 'nombre', e.target.value)} />
                </div>
                <div className="co-grid-2">
                  <div className="co-field">
                    <label className="co-label">Correo</label>
                    <input className="co-input" type="email" value={inst.correo} placeholder="correo@ejemplo.com"
                      onChange={e => actualizarCampo(inst.id, 'correo', e.target.value)} />
                  </div>
                  <div className="co-field">
                    <label className="co-label">Celular</label>
                    <input className="co-input" type="tel" value={inst.celular} placeholder="3001234567"
                      onChange={e => actualizarCampo(inst.id, 'celular', e.target.value)} />
                  </div>
                </div>

                {/* Programación */}
                <div className="co-divider" />
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>
                  <span className="co-label" style={{ margin: 0 }}>Programación mensual</span>
                  <span style={{ fontSize: 12, color: 'var(--ink-60)', fontFamily: 'var(--font-mono)' }}>{inst.programacion.length} mes{inst.programacion.length !== 1 ? 'es' : ''}</span>
                </div>

                {inst.programacion.length === 0 && (
                  <div className="co-empty">📅 Sin meses programados. Agrega el primero.</div>
                )}

                {inst.programacion.map((mes, mIdx) => (
                  <div key={mIdx} className="co-mes-block">
                    <div className="co-mes-head">
                      <div className="co-mes-title"><span className="co-mes-dot" />Mes {mes.mes}</div>
                      <button type="button" className="co-btn co-btn--danger" style={{ fontSize: 11, padding: '4px 10px' }}
                        onClick={() => eliminarMes(inst.id, mIdx)}><Ic.X /> Eliminar mes</button>
                    </div>
                    {mes.rangos.length === 0 && <p style={{ fontSize: 12, color: 'var(--ink-30)', fontStyle: 'italic', marginBottom: 8 }}>Sin rangos. Agrega uno.</p>}
                    {mes.rangos.map((rango, rIdx) => (
                      <div key={rIdx} className="co-rango-block">
                        <div className="co-rango-head">
                          <span className="co-rango-label">Rango {rIdx + 1}</span>
                          <button type="button" className="co-btn--icon-remove"
                            onClick={() => eliminarRango(inst.id, mIdx, rIdx)}><Ic.X /></button>
                        </div>
                        <div className="co-grid-2">
                          <div className="co-field">
                            <label className="co-label">Desde</label>
                            <input className="co-input" type="date" value={rango.desde}
                              onChange={e => actualizarRango(inst.id, mIdx, rIdx, 'desde', e.target.value)} />
                          </div>
                          <div className="co-field">
                            <label className="co-label">Hasta</label>
                            <input className="co-input" type="date" value={rango.hasta}
                              onChange={e => actualizarRango(inst.id, mIdx, rIdx, 'hasta', e.target.value)} />
                          </div>
                          <div className="co-field">
                            <label className="co-label">Hora inicio</label>
                            <input className="co-input" type="time" value={rango.hora_inicio}
                              onChange={e => actualizarRango(inst.id, mIdx, rIdx, 'hora_inicio', e.target.value)} />
                          </div>
                          <div className="co-field">
                            <label className="co-label">Hora fin</label>
                            <input className="co-input" type="time" value={rango.hora_fin}
                              onChange={e => actualizarRango(inst.id, mIdx, rIdx, 'hora_fin', e.target.value)} />
                          </div>
                        </div>
                      </div>
                    ))}
                    <button type="button" className="co-btn co-btn--dashed"
                      onClick={() => agregarRango(inst.id, mIdx)}><Ic.Plus /> Agregar rango de fechas</button>
                  </div>
                ))}

                <button type="button" className="co-btn co-btn--dashed-green"
                  onClick={() => agregarMes(inst.id)}><Ic.Calendar /> Agregar mes</button>
              </div>
            </div>
          );
        })}

        <button type="button" className="co-btn co-btn--ghost" style={{ width: '100%', marginTop: 4 }}
          onClick={agregarInstructor}><Ic.Plus /> Agregar instructor</button>
      </div>
    </div>
  );
};

