            {modo === 'regular' ? 'Nueva Oferta Regular' : 'Nueva Oferta Campesena'}
          </h1>
          <p className="co-banner-sub">
            {modo === 'regular'
              ? 'Formulario de creación con horario fijo y modalidad convencional'
              : 'Formulario especializado para programas campesinos con instructores múltiples'}
          </p>
          <div className="co-banner-pills">
            <span className={`co-pill co-pill--${modo === 'regular' ? 'regular' : 'inactive'}`}
              onClick={() => setModo('regular')}>🟢 Regular</span>
            <span className={`co-pill co-pill--${modo === 'campesena' ? 'campesena' : 'inactive'}`}
              onClick={() => setModo('campesena')}>🌾 Campesena</span>
          </div>
        </div>
        <div style={{ height: 32 }} />
      </div>

      {/* BODY */}
      <form onSubmit={e => e.preventDefault()}>
        <div className="co-body">

          {/* CARD 1: PROGRAMA */}
          <div className="co-card">
            <div className="co-card-head">
              <div className="co-card-icon"><Ic.Program /></div>
              <div className="co-card-title">Programa de Formación</div>
              <div className="co-card-num">01</div>
            </div>
            <div className="co-card-body">
              <div className="co-field">
                <label className="co-label">Programa</label>
                <Autocomplete
                  opciones={programas}
                  valorId={formData.programa_formacion}
                  onChange={id => setFormData({ ...formData, programa_formacion: id })}
                  placeholder="Nombre o código del programa..."
                  displayFn={p => `${p.nombre_programa} — ${p.codigo}`}
                  required
                />
              </div>
              <div className="co-grid-2">
                <div className="co-field">
                  <label className="co-label">Modalidad</label>
                  <select className="co-select" name="modalidad" value={formData.modalidad} onChange={handleChange} required>
                    <option value="">Seleccione...</option>
                    {modalidades.map(m => <option key={m._id} value={m._id}>{m.nombre}</option>)}
                  </select>
                </div>
                <div className="co-field">
                  <label className="co-label">Tipo de Oferta</label>
                  <select className="co-select" name="tipo_oferta" value={formData.tipo_oferta} onChange={handleChange} required>
                    <option value="">Seleccione...</option>
                    {tiposOferta.map(t => <option key={t._id} value={t._id}>{t.nombre}</option>)}
                  </select>
                </div>
              </div>
            </div>
          </div>

          {/* CARD 2: CUPOS Y AMBIENTE */}
          <div className="co-card">
            <div className="co-card-head">
              <div className="co-card-icon"><Ic.Users /></div>
              <div className="co-card-title">Cupos y Ambiente</div>
              <div className="co-card-num">02</div>
            </div>
            <div className="co-card-body">
              <div className="co-grid-2">
                <div className="co-field">
                  <label className="co-label">Cupo Máximo</label>
                  <input className="co-input" type="number" name="cupo_maximo" value={formData.cupo_maximo}
                    onChange={handleChange} placeholder="Ej: 30" min="1" required />
                </div>
                <div className="co-field">
                  <label className="co-label">Nombre del Ambiente</label>
                  <input className="co-input" type="text" name="ambiente.nombre" value={formData.ambiente.nombre}
                    onChange={handleChange} placeholder="Ej: Aula 101" required />
                </div>
              </div>
            </div>
          </div>

          {/* CARD 3: FECHAS */}
          <div className="co-card">
            <div className="co-card-head">
              <div className="co-card-icon"><Ic.Calendar /></div>
              <div className="co-card-title">Fechas</div>
              <div className="co-card-num">03</div>
            </div>
            <div className="co-card-body">
              <div className="co-grid-2">
                <div className="co-field">
                  <label className="co-label">Fecha Inicio</label>
                  <input className="co-input" type="date" name="fechas.inicio" value={formData.fechas.inicio} onChange={handleChange} required />
                </div>
                <div className="co-field">
                  <label className="co-label">Fecha Fin</label>
                  <input className="co-input" type="date" name="fechas.fin" value={formData.fechas.fin} onChange={handleChange} required />
                </div>
              </div>
            </div>
          </div>

          {/* CARD 4: UBICACIÓN */}
          <div className="co-card">
            <div className="co-card-head">
              <div className="co-card-icon"><Ic.Map /></div>
              <div className="co-card-title">Ubicación</div>
              <div className="co-card-num">04</div>
            </div>
            <div className="co-card-body">
              <div className="co-grid-3">
                <div className="co-field">
                  <label className="co-label">Departamento</label>
                  <input className="co-input" type="text" name="ubicacion.departamento" value={formData.ubicacion.departamento} onChange={handleChange} required />
                </div>
                <div className="co-field" style={{ gridColumn: 'span 2' }}>
                  <label className="co-label">Municipio</label>
                  <Autocomplete
                    opciones={municipios}
                    valorId={formData.ubicacion.municipio}
                    onChange={id => setFormData({ ...formData, ubicacion: { ...formData.ubicacion, municipio: id } })}
                    placeholder="Nombre del municipio..."
                    displayFn={m => m.nombre}
                    required
                  />
                </div>
              </div>
              <div className="co-field">
                <label className="co-label">Dirección</label>
                <input className="co-input" type="text" name="ubicacion.direccion" value={formData.ubicacion.direccion}
                  onChange={handleChange} placeholder="Calle 123 #45-67, Barrio Centro" required />
              </div>
            </div>
          </div>

          {/* CARD 5: EMPRESA */}
          <div className="co-card">
            <div className="co-card-head">
              <div className="co-card-icon"><Ic.Building /></div>
              <div className="co-card-title">Empresa Solicitante</div>
              <div className="co-card-num">05</div>
            </div>
            <div className="co-card-body">
              {!mostrarFormEmpresa ? (
                <>
                  {empresaSeleccionada && (
                    <div className="co-emp-selected">
                      <div className="co-emp-avatar">🏢</div>
                      <div>
                        <div className="co-emp-name">{empresaSeleccionada.nombre}</div>
                        <div className="co-emp-nit">NIT: {empresaSeleccionada.nit}</div>
                      </div>
                      <button type="button" className="co-btn co-btn--ghost" style={{ marginLeft: 'auto', fontSize: 12, padding: '6px 12px' }}
                        onClick={() => setFormData({ ...formData, empresa_solicitante: '' })}>Cambiar</button>
                    </div>
                  )}
                  {!empresaSeleccionada && (
                    <div className="co-field">
                      <label className="co-label">Seleccionar empresa</label>
                      <select className="co-select" name="empresa_solicitante" value={formData.empresa_solicitante} onChange={handleChange} required>
                        <option value="">Seleccione una empresa...</option>
                        {empresas.map(e => <option key={e._id} value={e._id}>{e.nombre} — NIT: {e.nit}</option>)}
                      </select>
                    </div>
                  )}
                  <button type="button" className="co-btn co-btn--ghost" style={{ marginTop: 6, fontSize: 13 }}
                    onClick={() => setMostrarFormEmpresa(true)}><Ic.Plus /> Crear nueva empresa</button>
                </>
              ) : (
                <div className="co-sub-form">
                  <div className="co-sub-title">Nueva empresa</div>
                  <div className="co-grid-2">
                    <div className="co-field" style={{ gridColumn: 'span 2' }}>
                      <label className="co-label">Nombre de la empresa</label>
                      <input className="co-input" value={nuevaEmpresa.nombre}
                        onChange={e => setNuevaEmpresa({ ...nuevaEmpresa, nombre: e.target.value })} placeholder="Razón social" />
                    </div>
                    <div className="co-field">
                      <label className="co-label">NIT</label>
                      <input className="co-input" value={nuevaEmpresa.nit}
                        onChange={e => setNuevaEmpresa({ ...nuevaEmpresa, nit: e.target.value })} placeholder="000000000-0" />
                    </div>
                    <div className="co-field">
                      <label className="co-label">Fecha de creación</label>
                      <input className="co-input" type="date" value={nuevaEmpresa.fecha_creacion}
                        onChange={e => setNuevaEmpresa({ ...nuevaEmpresa, fecha_creacion: e.target.value })} />
                    </div>
                    <div className="co-field">
                      <label className="co-label">Tipo de empresa</label>
                      <select className="co-select" value={nuevaEmpresa.tipo_empresa}
                        onChange={e => setNuevaEmpresa({ ...nuevaEmpresa, tipo_empresa: e.target.value })}>
                        {['Privada','Pública','Mixta','ONG','Fundación','Cooperativa','Otro'].map(t => <option key={t}>{t}</option>)}
                      </select>
                    </div>
                    <div className="co-field">
                      <label className="co-label">Dirección</label>
                      <input className="co-input" value={nuevaEmpresa.direccion}
                        onChange={e => setNuevaEmpresa({ ...nuevaEmpresa, direccion: e.target.value })} placeholder="Dirección completa" />
                    </div>
                    <div className="co-field">
                      <label className="co-label">N° de empleados</label>
                      <input className="co-input" type="number" value={nuevaEmpresa.numero_empleados} min="1"
                        onChange={e => setNuevaEmpresa({ ...nuevaEmpresa, numero_empleados: e.target.value })} placeholder="50" />
                    </div>
                  </div>

                  <div className="co-sub-title" style={{ marginTop: 16 }}>Representante Legal</div>
                  <div className="co-grid-2">
                    <div className="co-field" style={{ gridColumn: 'span 2' }}>
                      <label className="co-label">Nombre completo</label>
                      <input className="co-input" value={nuevaEmpresa.representante_legal.nombre_completo}
                        onChange={e => setNuevaEmpresa({ ...nuevaEmpresa, representante_legal: { ...nuevaEmpresa.representante_legal, nombre_completo: e.target.value } })} />
                    </div>
                    <div className="co-field">
                      <label className="co-label">Documento</label>
                      <input className="co-input" value={nuevaEmpresa.representante_legal.documento_identidad}
                        onChange={e => setNuevaEmpresa({ ...nuevaEmpresa, representante_legal: { ...nuevaEmpresa.representante_legal, documento_identidad: e.target.value } })} />
                    </div>
                    <div className="co-field">
                      <label className="co-label">Teléfono</label>
                      <input className="co-input" value={nuevaEmpresa.representante_legal.telefono}
                        onChange={e => setNuevaEmpresa({ ...nuevaEmpresa, representante_legal: { ...nuevaEmpresa.representante_legal, telefono: e.target.value } })} />
                    </div>
                    <div className="co-field" style={{ gridColumn: 'span 2' }}>
                      <label className="co-label">Correo</label>
                      <input className="co-input" type="email" value={nuevaEmpresa.representante_legal.correo}
                        onChange={e => setNuevaEmpresa({ ...nuevaEmpresa, representante_legal: { ...nuevaEmpresa.representante_legal, correo: e.target.value } })} />
                    </div>
                  </div>

                  <div className="co-sub-title" style={{ marginTop: 16 }}>Contacto en la Empresa</div>
                  <div className="co-grid-2">
                    <div className="co-field">
                      <label className="co-label">Nombre</label>
                      <input className="co-input" value={nuevaEmpresa.contacto.nombre_completo}
                        onChange={e => setNuevaEmpresa({ ...nuevaEmpresa, contacto: { ...nuevaEmpresa.contacto, nombre_completo: e.target.value } })} />
                    </div>
                    <div className="co-field">
                      <label className="co-label">Cargo</label>
                      <input className="co-input" value={nuevaEmpresa.contacto.cargo}
                        onChange={e => setNuevaEmpresa({ ...nuevaEmpresa, contacto: { ...nuevaEmpresa.contacto, cargo: e.target.value } })} />
                    </div>
                    <div className="co-field">
                      <label className="co-label">Teléfono</label>
                      <input className="co-input" value={nuevaEmpresa.contacto.telefono}
                        onChange={e => setNuevaEmpresa({ ...nuevaEmpresa, contacto: { ...nuevaEmpresa.contacto, telefono: e.target.value } })} />
                    </div>
                    <div className="co-field">
                      <label className="co-label">Correo</label>
                      <input className="co-input" type="email" value={nuevaEmpresa.contacto.correo}
                        onChange={e => setNuevaEmpresa({ ...nuevaEmpresa, contacto: { ...nuevaEmpresa.contacto, correo: e.target.value } })} />
                    </div>
                  </div>

                  <div style={{ display: 'flex', gap: 10, marginTop: 18 }}>
                    <button type="button" className="co-btn co-btn--primary" style={{ flex: 1 }}
                      onClick={() => {
                        const emp = { _id: Date.now().toString(), nombre: nuevaEmpresa.nombre, nit: nuevaEmpresa.nit };
                        setEmpresas([...empresas, emp]);
                        setFormData({ ...formData, empresa_solicitante: emp._id });
                        setMostrarFormEmpresa(false);
                      }}>
                      <Ic.Check /> Guardar empresa
                    </button>
                    <button type="button" className="co-btn co-btn--danger"
                      onClick={() => setMostrarFormEmpresa(false)}>Cancelar</button>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* CARD 6: DETALLES */}
          <div className="co-card">
            <div className="co-card-head">
              <div className="co-card-icon"><Ic.Star /></div>
              <div className="co-card-title">Detalles Adicionales</div>
              <div className="co-card-num">06</div>
            </div>
            <div className="co-card-body">
              <div className="co-grid-2">
                <div className="co-field">
                  <label className="co-label">Subsector Económico</label>
                  <input className="co-input" type="text" name="subsector_economico.nombre" value={formData.subsector_economico.nombre}
                    onChange={handleChange} placeholder="Ej: Tecnologías de la Información" required />
                </div>
                <div className="co-field">
                  <label className="co-label">Programa Especial</label>
                  <select className="co-select" name="programa_especial" value={formData.programa_especial} onChange={handleChange}>
                    <option value="">Ninguno</option>
                    {programasEspeciales.map(pe => <option key={pe._id} value={pe._id}>{pe.nombre}</option>)}
                  </select>
                </div>
              </div>
              <div className="co-field">
                <label className="co-label">Nombre del Convenio</label>
                <input className="co-input" type="text" name="convenio.nombre" value={formData.convenio.nombre}
                  onChange={handleChange} placeholder="Nombre del convenio" required />
              </div>
            </div>
          </div>

          {/* CARD HORARIO — solo regular */}
          {modo === 'regular' && (
            <div className="co-card">
              <div className="co-card-head">
                <div className="co-card-icon"><Ic.Clock /></div>
                <div className="co-card-title">Horario</div>
                <div className="co-card-num">07</div>
              </div>
              <div className="co-card-body">
                <div className="co-grid-2" style={{ marginBottom: 18 }}>
                  <div className="co-field">
                    <label className="co-label">Hora inicio</label>
                    <input className="co-input" type="time" name="horario.hora_inicio" value={formData.horario.hora_inicio} onChange={handleChange} required />
                  </div>
                  <div className="co-field">
                    <label className="co-label">Hora fin</label>
                    <input className="co-input" type="time" name="horario.hora_fin" value={formData.horario.hora_fin} onChange={handleChange} required />
                  </div>
                </div>
                <div className="co-field">
                  <label className="co-label">Días de la semana</label>
                  <div className="co-days">
                    {diasSemana.map(dia => (
                      <label key={dia} className={`co-day${formData.horario.dias.includes(dia) ? ' co-day--checked' : ''}`}
                        onClick={() => handleDia(dia)}>
                        <input type="checkbox" readOnly checked={formData.horario.dias.includes(dia)} />
                        {dia.slice(0, 3)}
                      </label>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* FORMULARIO CAMPESENA */}
          {modo === 'campesena' && (
            <FormularioCampesena formData={formData} setFormData={setFormData} />
          )}

          {/* DOCUMENTOS */}
          <div className="co-card">
            <div className="co-card-head">
              <div className="co-card-icon"><Ic.Clip /></div>
              <div className="co-card-title">Documentos Adjuntos</div>
              <div className="co-card-num">{modo === 'regular' ? '08' : '08'}</div>
            </div>
            <div className="co-card-body">
              <div className="co-grid-2">
                {/* Firma */}
                <div>
                  <label className="co-label">Firma Digital</label>
                  <div className={`co-file-zone${formData.firma_digital_pdf ? ' co-file-attached' : ''}`}
                    onClick={() => document.getElementById('firma_pdf_input').click()}>
                    <div className="co-file-icon">
                      {formData.firma_digital_pdf ? <Ic.CheckFile /> : <Ic.PDF />}
                    </div>
                    <div>
                      <div className="co-file-name">
                        {formData.firma_digital_pdf ? formData.firma_digital_pdf.name : 'Subir firma PDF'}
                      </div>
                      <div className="co-file-hint">PDF · máx. 5 MB</div>
                    </div>
                    {formData.firma_digital_pdf && (
                      <button type="button" className="co-file-remove"
                        onClick={e => { e.stopPropagation(); setFormData({ ...formData, firma_digital_pdf: null }); }}>✕</button>
                    )}
                  </div>
                  <input id="firma_pdf_input" type="file" accept=".pdf" className="co-file-input-hidden"
                    onChange={e => handleFile(e, 'firma_digital_pdf')} />
                </div>

                {/* Carta */}
                <div>
                  <label className="co-label">Carta Solicitante</label>
                  <div className={`co-file-zone${formData.carta_pdf ? ' co-file-attached' : ''}`}
                    onClick={() => document.getElementById('carta_pdf_input').click()}>
                    <div className="co-file-icon">
                      {formData.carta_pdf ? <Ic.CheckFile /> : <Ic.PDF />}
                    </div>
                    <div>
                      <div className="co-file-name">
                        {formData.carta_pdf ? formData.carta_pdf.name : 'Subir carta PDF'}
                      </div>
                      <div className="co-file-hint">PDF · máx. 5 MB</div>
                    </div>
                    {formData.carta_pdf && (
                      <button type="button" className="co-file-remove"
                        onClick={e => { e.stopPropagation(); setFormData({ ...formData, carta_pdf: null }); }}>✕</button>
                    )}
                  </div>
                  <input id="carta_pdf_input" type="file" accept=".pdf" className="co-file-input-hidden"
                    onChange={e => handleFile(e, 'carta_pdf')} />
                </div>
              </div>
            </div>
          </div>

        </div>

        {/* STICKY SUBMIT BAR */}
        <div className="co-submit-bar">
          <button type="button" className="co-back-btn">← Cancelar</button>
          <button type="submit" className="co-submit-btn" disabled={loading}>
            {loading ? 'Guardando...' : <><Ic.Send /> Guardar Oferta</>}
          </button>
        </div>
      </form>
    </div>
  );
};

export default CrearOferta;
